sql:
SELECT best_selling_drive
  FROM sales_reports
  WHERE report_date = (SELECT MAX(report_date) FROM sales_reports);

SELECT report_date, total_sales, best_selling_drive
FROM sales_reports
ORDER BY report_date DESC;

external_knowledge:
- 'top-selling' refers to the tape drive models with the highest total quantity sold; 
- 'last quarter' refers to the period of 3 months prior to the current date; 
- 'current quantity available' refers to the total stock level of each tape drive model in each warehouse.

- 'Sales performance' is measured by both the quantity sold and the sales amount; 
- 'Best and worst-selling' refer to the top and bottom ranks according to these metrics; 
- 'Customer feedback ratings' are considered but not the primary basis for 'sales performance'.
